// Solution
#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
int binarySearch(vector<int>& arr, int target) {
	int low = 0, high = arr.size() - 1;
	while (low <= high) {
		int mid = low + (high - low) / 2;
		if (arr[mid] == target) return mid;
		else if (arr[mid] < target) {
			low = mid + 1;
		} else {
			low = mid;
		}
	}
	return -1;
}
};
int main() {
	Solution solution;
	vector<int> arr = {1, 2, 3, 4, 5};
	int target = 5;
	cout << solution.binarySearch(arr, target) << endl;
	return 0;
}

