class Solution:
    def binarySearch(self, arr, target):
        low = 0
        high = len(arr) - 1
        while low <= high:
            mid = (low + high) // 2
            if arr[mid] == target:
                return mid
            elif arr[mid] < target:
                low = mid + 1
            else:
                low = mid
        return -1
if __name__ == '__main__':
    solution = Solution()
    arr = [1, 2, 3, 4, 5]
    target = 5
    print(solution.binarySearch(arr, target))

